insert into pieces_justificatives (demarche_id, items) values ('cni_passeport', '["Adresse mail + mot de passe du compte mail (si existant)","État civil complet des deux parents (noms, prénoms, dates et lieux de naissance) ou livret de famille / actes de naissance","Taille et couleur des yeux","Justificatif de domicile < 6 mois","Savoir pourquoi on est français (mariage, déclaration, décret, filiation)","Passeport : timbre fiscal acheté en amont — 17 € (<15 ans), 42 € (15-18), 86 € (majeur)","Perte/vol CNI : timbre fiscal 25 €"]'::jsonb) on conflict (demarche_id) do update set items = excluded.items;
